class Solution {
public:
    int maxNonOverlappingIntervals(int N, vector<pair<int,int>>& intervals) {
        sort(intervals.begin(), intervals.end(), [](auto &left, auto &right) {
            return left.second < right.second;
        });

        int lastEnd = -1;
        int count = 0;

        for (auto interval : intervals) {
            if (interval.first <= lastEnd) {
                continue;
            } else {
                lastEnd = interval.second;
                count++;
            }
        }

        return count;
    }
};

