    int lastEnd = -1;
    int count = 0;

    for (int i = 0; i < N; i++) {
        if (intervals[i][0] <= lastEnd) {
            continue;
        } else {
            lastEnd = intervals[i][1];
            count++;
        }
    }

    return count;
