class Solution {
    maxNonOverlappingIntervals(N, intervals) {
        intervals.sort((a, b) => a.end - b.end);

        let lastEnd = -1;
        let count = 0;

        for (const interval of intervals) {
            if (interval.start <= lastEnd) {
                continue;
            } else {
                lastEnd = interval.end;
                count++;
            }
        }

        return count;
    }
